 		 * If a folio at the tail of the LRU is under writeback, there
@@ -1693,12 +1673,14 @@ static unsigned long isolate_lru_folios(unsigned long nr_to_scan,
 	unsigned long nr_zone_taken[MAX_NR_ZONES] = { 0 };
