90- * If a full scan of the inactive list fails to free enough memory then we\nmm/vmscan.c-6491- * are \"out of memory\" and something needs to be killed.\nmm/vmscan.c-6492- *\nmm/vmscan.c-6493- * If the caller is !__GFP_FS then the probability of a failure is reasonably\nmm/vmscan.c:6494: * high - the zone may be full of dirty or under-writeback pages, which this\nmm/vmscan.c:6495: * caller can't do much about.  We kick the writeback threads and take explicit\nmm/vmscan.c-6496- * naps in the hope that some of these pages can be written.  But if the\nmm/vmscan.c-6497- * allocating task holds filesystem locks which prevent writeout this might not\nmm/vmscan.c-6498- * work, and the allocation attempt will fail.\nmm/vmscan.c-6499- *\nmm/vmscan.c-6500- * returns:\t0, if no pages reclaimed\n--\nmm/vmscan.c-6980-\t\treturn true;\nmm/vmscan.c-6981-\nmm/vmscan.c-6982-\treturn false;\nmm/vmscan.c-6983-}\nmm/vmscan.c-6984-\nmm/vmscan.c:6985:/* Clear pgdat state for congested, dirty or under writeback. */\nmm/vmscan.c-6986-static void clear_pgdat_congested(pg_data_t *pgdat)\nmm/vmscan.c-6987-{\nmm/vmscan.c-6988-\tstruct lruvec *lruvec = mem_cgroup_lruvec(NULL, pgdat);\nmm/vmscan.c-6989-\nmm/vmscan.c-6990-\tclear_bit(LRUVEC_NODE_CONGESTED, &lruvec->flags);\n--\nmm/vmscan.c-7032-/*\nmm/vmscan.c-7033- * kswapd shrinks a node of pages that are at or below the highest usable\nmm/vmscan.c-7034- * zone that is currently unbalanced.\nmm/vmscan.c-7035- *\nmm/vmscan.c-7036- * Returns true if kswapd scanned at least the requested number of pages to\nmm/vmscan.c:7037: * reclaim or if the lack of progress was due to pages under writeback.\nmm/vmscan.c-7038- * This is used to determine if the scanning priority needs to be raised.\nmm/vmscan.c-7039- */\nmm/vmscan.c-7040-static bool kswapd_shrink_node(pg_data_t *pgdat,\nmm/vmscan.c-7041-\t\t\t       struct scan_control *sc)\nmm/vmscan.c-7042-{\n--\nmm/vmscan.c-7196-\t\t * buffer_heads_over_limit may have adjusted it.\nmm/vmscan.c-7197-\t\t */