    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0-only\n/*\n *  linux/fs/buffer.c\n *\n *  Copyright (C) 1991, 1992, 2002  Linus Torvalds\n */\n\n/*\n * Start bdflush() with kernel_thread not syscall - Paul Gortmaker, 12/95\n *\n * Removed a lot of unnecessary code and simplified things now that\n * the buffer cache isn't our primary cache - Andrew Tridgell 12/96\n *\n * Speed up hash, lru, and free list operations.  Use gfp() for allocating\n * hash table, use SLAB cache for buffer heads. SMP threading.  -DaveM\n *\n * Added 32k buffer block sizes - these are required older ARM systems. - RMK\n *\n * async buffer flushing, 1999 Andrea Arcangeli <andrea@suse.de>\n */\n\n#include <linux/kernel.h>\n#include <linux/sched/signal.h>\n#include <linux/syscalls.h>\n#include <linux/fs.h>\n#include <linux/iomap.h>\n#include <linux/mm.h>\n#include <linux/percpu.h>\n#include <linux/slab.h>\n#include <linux/capability.h>\n#include <linux/blkdev.h>\n#include <linux/blk-crypto.h>\n#include <linux/file.h>\n#include <linux/quotaops.h>\n#include <linux/highmem.h>\n#include <linux/export.h>\n#include <linux/backing-dev.h>\n#include <linux/writeback.h>\n#include <linux/hash.h>\n#include <linux/suspend.h>\n#include <linux/buffer_head.h>\n#include <linux/task_io_accounting_ops.h>\n#include <linux/bio.h>\n#include <linux/cpu.h>\n#include <linux/bitops.h>\n#include <linux/mpage.h>\n#include <linux/bit_spinlock.h>\n#include <linux/folio_batch.h>\n#include <linux/sched/mm.h>\n#include <trace/events/block.h>\n#include <linux/fscrypt.h>\n#include <linux/fsverity.h>\n#include <linux/sched/isolation.h>\n\n#include \"internal.h\"\n\nstatic int fsync_buffers_list(spinlock_t *lock, struct list_head *list);\nstatic void submit_bh_wbc(blk_opf_t opf, struct buffer_head *bh,\n\t\t\t  enum rw_hint hint, struct writeback_control *wbc);\n\n#define BH_ENTRY(list) list_entry((list), struct buffer_head, b_assoc_buffers)\n\ninline void touch_buffer(struct buffer_head *bh)\n{\n\ttrace_block_touch_buffer(bh);\n\tfolio_mark_accessed(bh->b_folio);\n}\nEXPORT_SYMBOL(touch_buffer);\n\nvoid __lock_buffer(struct buffer_head *bh)\n{\n\twait_on_bit_lock_io(&bh->b_state, BH_Lock, TASK_UNINTERRUPTIBLE);\n}\nEXPORT_SYMBOL(__lock_buffer);\n\nvoid unlock_buffer(struct buffer_head *bh)\n{\n\tclear_bit_unlock(BH_Lock, &bh->b_state);\n\tsmp_mb__after_atomic();\n\twake_up_bit(&bh->b_state, BH_Lock);\n}\nEXPORT_SYMBOL(unlock_buffer);\n\n/*\n * Returns if the folio has dirty or writeback buffers. If all the buffers\n * are unlocked and clean then the folio_test_dirty information is stale. If\n * any of the buffers are locked, it is assumed they are locked for IO.\n */\nvoid buffer_check_dirty_writeback(struct folio *folio,\n\t\t\t\t     bool *dirty, bool *writeback)\n{\n\tstruct buffer_head *head, *bh;\n\t*dirty = false;\n\t*writeback = false;\n\n\tBUG_ON(!folio_test_locked(folio));\n\n\thead = folio_buffers(folio);\n\tif (!head)\n\t\treturn;\n\n\tif (folio_test_writeback(folio))\n\t\t*writeback = true;\n\n\tbh = head;\n\tdo {\n\t\tif (buffer_locked(bh))\n\t\t\t*writeback = true;\n\n\t\tif (buffer_dirty(bh))\n\t\t\t*dirty = true;\n\n\t\tbh = bh->b_this_page;\n\t} while (bh != head);\n}\n\n/*\n * Block until a buffer comes unlocked.  This doesn't stop it\n * from becoming locked again - you have to lock it yourself\n * if you want to preserve its state.\n */\nvoid __wait_on_buffer(struct buffer_head * bh)\n{\n\twait_on_bit_io(&bh->b_state, BH_Lock, TASK_UNINTERRUPTIBLE);\n}\nEXPORT_SYMBOL(__wait_on_buffer);\n\nstatic void buffer_io_error(struct buffer_head *bh, char *msg)\n{\n\tif (!test_bit(BH_Quiet, &bh->b_state))\n\t\tprintk_ratelimited(KERN_ERR\n\t\t\t\"Buffer I/O error on dev %pg, logical block %llu%s\\n\",\n\t\t\tbh->b_bdev, (unsigned long long)bh->b_blocknr, msg);\n}\n\n/*\n * End-of-IO handler helper function which does not touch the bh after\n * unlocking it.\n * Note: unlock_buffer() sort-of does touch the bh after unlocking it, but\n * a race there is benign: unlock_buffer() only use the bh's address for\n * hashing after unlocking the buffer, so it doesn't actually touch the bh\n * itself.\n */\nstatic void __end_buffer_read_notouch(struct buffer_head *bh, int uptodate)\n{\n\tif (uptodate) {\n\t\tset_buffer_uptodate(bh);\n\t} else {\n\t\t/* This happens, due to failed read-ahead attempts. */\n\t\tclear_buffer_uptodate(bh);\n\t}\n\tunlock_buffer(bh);\n}\n\n/*\n * Default synchronous end-of-IO handler..  Just mark it up-to-date and\n * unlock the buffer.\n */\nvoid end_buffer_read_sync(struct buffer_head *bh, int uptodate)\n{\n\tput_bh(bh);\n\t__end_buffer_read_notouch(bh, uptodate);\n}\nEXPORT_SYMBOL(end_buffer_read_sync);\n\nvoid end_buffer_write_sync(struct buffer_head *bh, int uptodate)\n{\n\tif (uptodate) {\n\t\tset_buffer_uptodate(bh);\n\t} else {\n\t\tbuffer_io_error(bh, \", lost sync page write\");\n\t\tmark_buffer_write_io_error(bh);\n\t\tclear_buffer_uptodate(bh);\n\t}\n\tunlock_buffer(bh);\n\tput_bh(bh);\n}\nEXPORT_SYMBOL(end_buffer_write_sync);\n\nstatic struct buffer_head *\n__find_get_block_slow(struct block_device *bdev, sector_t block, bool atomic)\n{\n\tstruct address_space *bd_mapping = bdev->bd_mapping;\n\tconst int blkbits = bd_mapping->host->i_blkbits;\n\tstruct buffer_head *ret = NULL;\n\tpgoff_t index;\n\tstruct buffer_head *bh;\n\tstruct buffer_head *head;\n\tstruct folio *folio;\n\tint all_mapped = 1;\n\tstatic DEFINE_RATELIMIT_STATE(last_warned, HZ, 1);\n\n\tindex = ((loff_t)block << blkbits) / PAGE_SIZE;\n\tfolio = __filemap_get_folio(bd_mapping, index, FGP_ACCESSED, 0);\n\tif (IS_ERR(folio))\n\t\tgoto out;\n\n\t/*\n\t * Folio lock protects the buffers. Callers that cannot block\n\t * will fallback to serializing vs try_to_free_buffers() via\n\t * the i_private_lock.\n\t */\n\tif (atomic)\n\t\tspin_lock(&bd_mapping->i_private_lock);\n\telse\n\t\tfolio_lock(folio);\n\n\thead = folio_buffers(folio);\n\tif (!head)\n\t\tgoto out_unlock;\n\t/*\n\t * Upon a noref migration, the folio lock serializes here;\n\t * otherwise bail.\n\t */\n\tif (test_bit_acquire(BH_Migrate, &head->b_state)) {\n\t\tWARN_ON(!atomic);\n\t\tgoto out_unlock;\n\t}\n\n\tbh = head;\n\tdo {\n\t\tif (!buffer_mapped(bh))\n\t\t\tall_mapped = 0;\n\t\telse if (bh->b_blocknr == block) {\n\t\t\tret = bh;\n\t\t\tget_bh(bh);\n\t\t\tgoto out_unlock;\n\t\t}\n\t\tbh = bh->b_this_page;\n\t} while (bh != head);\n\n\t/* we might be here because some of the buffers on this page are\n\t * not mapped.  This is due to various races between\n\t * file io on the block device and getblk.  It gets dealt with\n\t * elsewhere, don't buffer_error if we had some unmapped buffers\n\t */\n\tratelimit_set_flags(&last_warned, RATELIMIT_MSG_ON_RELEASE);\n\tif (all_mapped && __ratelimit(&last_warned)) {\n\t\tprintk(\"__find_get_block_slow() failed. block=%llu, \"\n\t\t       \"b_blocknr=%llu, b_state=0x%08lx, b_size=%zu, \"\n\t\t       \"device %pg blocksize: %d\\n\",\n\t\t       (unsigned long long)block,\n\t\t       (unsigned long long)bh->b_blocknr,\n\t\t       bh->b_state, bh->b_size, bdev,\n\t\t       1 << blkbits);\n\t}\nout_unlock:\n\tif (atomic)\n\t\tspin_unlock(&bd_mapping->i_private_lock);\n\telse\n\t\tfolio_unlock(folio);\n\tfolio_put(folio);\nout:\n\treturn ret;\n}\n\nstatic void end_buffer_async_read(struct buffer_head *bh, int uptodate)\n{\n\tunsigned long flags;\n\tstruct buffer_head *first;\n\tstruct buffer_head *tmp;\n\tstruct folio *folio;\n\tint folio_uptodate = 1;\n\n\tBUG_ON(!buffer_async_read(bh));\n\n\tfolio = bh->b_folio;\n\tif (uptodate) {\n\t\tset_buffer_uptodate(bh);\n\t} else {\n\t\tclear_buffer_uptodate(bh);\n\t\tbuffer_io_error(bh, \", async page read\");\n\t}\n\n\t/*\n\t * Be _very_ careful from here on. Bad things can happen if\n\t * two buffer heads end IO at almost the same time and both\n\t * decide that the page is now completely done.\n\t */\n\tfirst = folio_buffers(folio);\n\tspin_lock_irqsave(&first->b_uptodate_lock, flags);\n\tclear_buffer_async_read(bh);\n\tunlock_buffer(bh);\n\ttmp = bh;\n\tdo {\n\t\tif (!buffer_uptodate(tmp))\n\t\t\tfolio_uptodate = 0;\n\t\tif (buffer_async_read(tmp)) {\n\t\t\tBUG_ON(!buffer_locked(tmp));\n\t\t\tgoto still_busy;\n\t\t}\n\t\ttmp = tmp->b_this_page;\n\t} while (tmp != bh);\n\tspin_unlock_irqrestore(&first->b_uptodate_lock, flags);\n\n\tfolio_end_read(folio, folio_uptodate);\n\treturn;\n\nstill_busy:\n\tspin_unlock_irqrestore(&first->b_uptodate_lock, flags);\n}\n\nstruct postprocess_bh_ctx {\n\tstruct work_struct work;\n\tstruct buffer_head *bh;\n\tstruct fsverity_info *vi;\n};\n\nstatic void verify_bh(struct work_struct *work)\n{\n\tstruct postprocess_bh_ctx *ctx =\n\t\tcontainer_of(work, struct postprocess_bh_ctx, work);\n\tstruct buffer_head *bh = ctx->bh;\n\tbool valid;\n\n\tvalid = fsverity_verify_blocks(ctx->vi, bh->b_folio, bh->b_size,\n\t\t\t\t       bh_offset(bh));\n\tend_buffer_async_read(bh, valid);\n\tkfree(ctx);\n}\n\nstatic void decrypt_bh(struct work_struct *work)\n{\n\tstruct postprocess_bh_ctx *ctx =\n\t\tcontainer_of(work, struct postprocess_bh_ctx, work);\n\tstruct buffer_head *bh = ctx->bh;\n\tint err;\n\n\terr = fscrypt_decrypt_pagecache_blocks(bh->b_folio, bh->b_size,\n\t\t\t\t\t       bh_offset(bh));\n\tif (err == 0 && ctx->vi) {\n\t\t/*\n\t\t * We use different work queues for decryption and for verity\n\t\t * because verity may require reading metadata pages that need\n\t\t * decryption, and we shouldn't recurse to the same workqueue.\n\t\t */\n\t\tINIT_WORK(&ctx->work, verify_bh);\n\t\tfsverity_enqueue_verify_work(&ctx->work);\n\t\treturn;\n\t}\n\tend_buffer_async_read(bh, err == 0);\n\tkfree(ctx);\n}\n\n/*\n * I/O completion handler for block_read_full_folio() - pages\n * which come unlocked at the end of I/O.\n */\nstatic void end_buffer_async_read_io(struct buffer_head *bh, int uptodate)\n{\n\tstruct inode *inode = bh->b_folio->mapping->host;\n\tbool decrypt = fscrypt_inode_uses_fs_layer_crypto(inode);\n\tstruct fsverity_info *vi = NULL;\n\n\t/* needed by ext4 */\n\tif (bh->b_folio->index < DIV_ROUND_UP(inode->i_size, PAGE_SIZE))\n\t\tvi = fsverity_get_info(inode);\n\n\t/* Decrypt (with fscrypt) and/or verify (with fsverity) if needed. */\n\tif (uptodate && (decrypt || vi)) {\n\t\tstruct postprocess_bh_ctx *ctx = kmalloc_obj(*ctx, GFP_ATOMIC);\n\n\t\tif (ctx) {\n\t\t\tctx->bh = bh;\n\t\t\tctx->vi = vi;\n\t\t\tif (decrypt) {\n\t\t\t\tINIT_WORK(&ctx->work, decrypt_bh);\n\t\t\t\tfscrypt_enqueue_decrypt_work(&ctx->work);\n\t\t\t} else {\n\t\t\t\tINIT_WORK(&ctx->work, verify_bh);\n\t\t\t\tfsverity_enqueue_verify_work(&ctx->work);\n\t\t\t}\n\t\t\treturn;\n\t\t}\n\t\tuptodate = 0;\n\t}\n\tend_buffer_async_read(bh, uptodate);\n}\n\n/*\n * Completion handler for block_write_full_folio() - folios which are unlocked\n * during I/O, and which have the writeback flag cleared upon I/O completion.\n */\nstatic void end_buffer_async_write(struct buffer_head *bh, int uptodate)\n{\n\tunsigned long flags;\n\tstruct buffer_head *first;\n\tstruct buffer_head *tmp;\n\tstruct folio *folio;\n\n\tBUG_ON(!buffer_async_write(bh));\n\n\tfolio = bh->b_folio;\n\tif (uptodate) {\n\t\tset_buffer_uptodate(bh);\n\t} else {\n\t\tbuffer_io_error(bh, \", lost async page write\");\n\t\tmark_buffer_write_io_error(bh);\n\t\tclear_buffer_uptodate(bh);\n\t}\n\n... [Diff truncated. Dropped 2363 lines] ...\n\nEXPORT_SYMBOL(generic_block_bmap);\n\nstatic void end_bio_bh_io_sync(struct bio *bio)\n{\n\tstruct buffer_head *bh = bio->bi_private;\n\n\tif (unlikely(bio_flagged(bio, BIO_QUIET)))\n\t\tset_bit(BH_Quiet, &bh->b_state);\n\n\tbh->b_end_io(bh, !bio->bi_status);\n\tbio_put(bio);\n}\n\nstatic void submit_bh_wbc(blk_opf_t opf, struct buffer_head *bh,\n\t\t\t  enum rw_hint write_hint,\n\t\t\t  struct writeback_control *wbc)\n{\n\tconst enum req_op op = opf & REQ_OP_MASK;\n\tstruct bio *bio;\n\n\tBUG_ON(!buffer_locked(bh));\n\tBUG_ON(!buffer_mapped(bh));\n\tBUG_ON(!bh->b_end_io);\n\tBUG_ON(buffer_delay(bh));\n\tBUG_ON(buffer_unwritten(bh));\n\n\t/*\n\t * Only clear out a write error when rewriting\n\t */\n\tif (test_set_buffer_req(bh) && (op == REQ_OP_WRITE))\n\t\tclear_buffer_write_io_error(bh);\n\n\tif (buffer_meta(bh))\n\t\topf |= REQ_META;\n\tif (buffer_prio(bh))\n\t\topf |= REQ_PRIO;\n\n\tbio = bio_alloc(bh->b_bdev, 1, opf, GFP_NOIO);\n\n\tfscrypt_set_bio_crypt_ctx_bh(bio, bh, GFP_NOIO);\n\n\tbio->bi_iter.bi_sector = bh->b_blocknr * (bh->b_size >> 9);\n\tbio->bi_write_hint = write_hint;\n\n\tbio_add_folio_nofail(bio, bh->b_folio, bh->b_size, bh_offset(bh));\n\n\tbio->bi_end_io = end_bio_bh_io_sync;\n\tbio->bi_private = bh;\n\n\t/* Take care of bh's that straddle the end of the device */\n\tguard_bio_eod(bio);\n\n\tif (wbc) {\n\t\twbc_init_bio(wbc, bio);\n\t\twbc_account_cgroup_owner(wbc, bh->b_folio, bh->b_size);\n\t}\n\n\tblk_crypto_submit_bio(bio);\n}\n\nvoid submit_bh(blk_opf_t opf, struct buffer_head *bh)\n{\n\tsubmit_bh_wbc(opf, bh, WRITE_LIFE_NOT_SET, NULL);\n}\nEXPORT_SYMBOL(submit_bh);\n\nvoid write_dirty_buffer(struct buffer_head *bh, blk_opf_t op_flags)\n{\n\tlock_buffer(bh);\n\tif (!test_clear_buffer_dirty(bh)) {\n\t\tunlock_buffer(bh);\n\t\treturn;\n\t}\n\tbh->b_end_io = end_buffer_write_sync;\n\tget_bh(bh);\n\tsubmit_bh(REQ_OP_WRITE | op_flags, bh);\n}\nEXPORT_SYMBOL(write_dirty_buffer);\n\n/*\n * For a data-integrity writeout, we need to wait upon any in-progress I/O\n * and then start new I/O and then wait upon it.  The caller must have a ref on\n * the buffer_head.\n */\nint __sync_dirty_buffer(struct buffer_head *bh, blk_opf_t op_flags)\n{\n\tWARN_ON(atomic_read(&bh->b_count) < 1);\n\tlock_buffer(bh);\n\tif (test_clear_buffer_dirty(bh)) {\n\t\t/*\n\t\t * The bh should be mapped, but it might not be if the\n\t\t * device was hot-removed. Not much we can do but fail the I/O.\n\t\t */\n\t\tif (!buffer_mapped(bh)) {\n\t\t\tunlock_buffer(bh);\n\t\t\treturn -EIO;\n\t\t}\n\n\t\tget_bh(bh);\n\t\tbh->b_end_io = end_buffer_write_sync;\n\t\tsubmit_bh(REQ_OP_WRITE | op_flags, bh);\n\t\twait_on_buffer(bh);\n\t\tif (!buffer_uptodate(bh))\n\t\t\treturn -EIO;\n\t} else {\n\t\tunlock_buffer(bh);\n\t}\n\treturn 0;\n}\nEXPORT_SYMBOL(__sync_dirty_buffer);\n\nint sync_dirty_buffer(struct buffer_head *bh)\n{\n\treturn __sync_dirty_buffer(bh, REQ_SYNC);\n}\nEXPORT_SYMBOL(sync_dirty_buffer);\n\nstatic inline int buffer_busy(struct buffer_head *bh)\n{\n\treturn atomic_read(&bh->b_count) |\n\t\t(bh->b_state & ((1 << BH_Dirty) | (1 << BH_Lock)));\n}\n\nstatic bool\ndrop_buffers(struct folio *folio, struct buffer_head **buffers_to_free)\n{\n\tstruct buffer_head *head = folio_buffers(folio);\n\tstruct buffer_head *bh;\n\n\tbh = head;\n\tdo {\n\t\tif (buffer_busy(bh))\n\t\t\tgoto failed;\n\t\tbh = bh->b_this_page;\n\t} while (bh != head);\n\n\tdo {\n\t\tstruct buffer_head *next = bh->b_this_page;\n\n\t\tif (bh->b_assoc_map)\n\t\t\t__remove_assoc_queue(bh);\n\t\tbh = next;\n\t} while (bh != head);\n\t*buffers_to_free = head;\n\tfolio_detach_private(folio);\n\treturn true;\nfailed:\n\treturn false;\n}\n\n/**\n * try_to_free_buffers - Release buffers attached to this folio.\n * @folio: The folio.\n *\n * If any buffers are in use (dirty, under writeback, elevated refcount),\n * no buffers will be freed.\n *\n * If the folio is dirty but all the buffers are clean then we need to\n * be sure to mark the folio clean as well.  This is because the folio\n * may be against a block device, and a later reattachment of buffers\n * to a dirty folio will set *all* buffers dirty.  Which would corrupt\n * filesystem data on the same device.\n *\n * The same applies to regular filesystem folios: if all the buffers are\n * clean then we set the folio clean and proceed.  To do that, we require\n * total exclusion from block_dirty_folio().  That is obtained with\n * i_private_lock.\n *\n * Exclusion against try_to_free_buffers may be obtained by either\n * locking the folio or by holding its mapping's i_private_lock.\n *\n * Context: Process context.  @folio must be locked.  Will not sleep.\n * Return: true if all buffers attached to this folio were freed.\n */\nbool try_to_free_buffers(struct folio *folio)\n{\n\tstruct address_space * const mapping = folio->mapping;\n\tstruct buffer_head *buffers_to_free = NULL;\n\tbool ret = 0;\n\n\tBUG_ON(!folio_test_locked(folio));\n\tif (folio_test_writeback(folio))\n\t\treturn false;\n\n\t/* Misconfigured folio check */\n\tif (WARN_ON_ONCE(!folio_buffers(folio)))\n\t\treturn true;\n\n\tif (mapping == NULL) {\t\t/* can this still happen? */\n\t\tret = drop_buffers(folio, &buffers_to_free);\n\t\tgoto out;\n\t}\n\n\tspin_lock(&mapping->i_private_lock);\n\tret = drop_buffers(folio, &buffers_to_free);\n\n\t/*\n\t * If the filesystem writes its buffers by hand (eg ext3)\n\t * then we can have clean buffers against a dirty folio.  We\n\t * clean the folio here; otherwise the VM will never notice\n\t * that the filesystem did any IO at all.\n\t *\n\t * Also, during truncate, discard_buffer will have marked all\n\t * the folio's buffers clean.  We discover that here and clean\n\t * the folio also.\n\t *\n\t * i_private_lock must be held over this entire operation in order\n\t * to synchronise against block_dirty_folio and prevent the\n\t * dirty bit from being lost.\n\t */\n\tif (ret)\n\t\tfolio_cancel_dirty(folio);\n\tspin_unlock(&mapping->i_private_lock);\nout:\n\tif (buffers_to_free) {\n\t\tstruct buffer_head *bh = buffers_to_free;\n\n\t\tdo {\n\t\t\tstruct buffer_head *next = bh->b_this_page;\n\t\t\tfree_buffer_head(bh);\n\t\t\tbh = next;\n\t\t} while (bh != buffers_to_free);\n\t}\n\treturn ret;\n}\nEXPORT_SYMBOL(try_to_free_buffers);\n\n/*\n * Buffer-head allocation\n */\nstatic struct kmem_cache *bh_cachep __ro_after_init;\n\n/*\n * Once the number of bh's in the machine exceeds this level, we start\n * stripping them in writeback.\n */\nstatic unsigned long max_buffer_heads __ro_after_init;\n\nint buffer_heads_over_limit;\n\nstruct bh_accounting {\n\tint nr;\t\t\t/* Number of live bh's */\n\tint ratelimit;\t\t/* Limit cacheline bouncing */\n};\n\nstatic DEFINE_PER_CPU(struct bh_accounting, bh_accounting) = {0, 0};\n\nstatic void recalc_bh_state(void)\n{\n\tint i;\n\tint tot = 0;\n\n\tif (__this_cpu_inc_return(bh_accounting.ratelimit) - 1 < 4096)\n\t\treturn;\n\t__this_cpu_write(bh_accounting.ratelimit, 0);\n\tfor_each_online_cpu(i)\n\t\ttot += per_cpu(bh_accounting, i).nr;\n\tbuffer_heads_over_limit = (tot > max_buffer_heads);\n}\n\nstruct buffer_head *alloc_buffer_head(gfp_t gfp_flags)\n{\n\tstruct buffer_head *ret = kmem_cache_zalloc(bh_cachep, gfp_flags);\n\tif (ret) {\n\t\tINIT_LIST_HEAD(&ret->b_assoc_buffers);\n\t\tspin_lock_init(&ret->b_uptodate_lock);\n\t\tpreempt_disable();\n\t\t__this_cpu_inc(bh_accounting.nr);\n\t\trecalc_bh_state();\n\t\tpreempt_enable();\n\t}\n\treturn ret;\n}\nEXPORT_SYMBOL(alloc_buffer_head);\n\nvoid free_buffer_head(struct buffer_head *bh)\n{\n\tBUG_ON(!list_empty(&bh->b_assoc_buffers));\n\tkmem_cache_free(bh_cachep, bh);\n\tpreempt_disable();\n\t__this_cpu_dec(bh_accounting.nr);\n\trecalc_bh_state();\n\tpreempt_enable();\n}\nEXPORT_SYMBOL(free_buffer_head);\n\nstatic int buffer_exit_cpu_dead(unsigned int cpu)\n{\n\tint i;\n\tstruct bh_lru *b = &per_cpu(bh_lrus, cpu);\n\n\tfor (i = 0; i < BH_LRU_SIZE; i++) {\n\t\tbrelse(b->bhs[i]);\n\t\tb->bhs[i] = NULL;\n\t}\n\tthis_cpu_add(bh_accounting.nr, per_cpu(bh_accounting, cpu).nr);\n\tper_cpu(bh_accounting, cpu).nr = 0;\n\treturn 0;\n}\n\n/**\n * bh_uptodate_or_lock - Test whether the buffer is uptodate\n * @bh: struct buffer_head\n *\n * Return true if the buffer is up-to-date and false,\n * with the buffer locked, if not.\n */\nint bh_uptodate_or_lock(struct buffer_head *bh)\n{\n\tif (!buffer_uptodate(bh)) {\n\t\tlock_buffer(bh);\n\t\tif (!buffer_uptodate(bh))\n\t\t\treturn 0;\n\t\tunlock_buffer(bh);\n\t}\n\treturn 1;\n}\nEXPORT_SYMBOL(bh_uptodate_or_lock);\n\n/**\n * __bh_read - Submit read for a locked buffer\n * @bh: struct buffer_head\n * @op_flags: appending REQ_OP_* flags besides REQ_OP_READ\n * @wait: wait until reading finish\n *\n * Returns zero